	switch strings.ToLower(format) {
	case "csv.gz", "gz":
		gr, err := gzip.NewReader(r)
		if err != nil {
			return nil, fmt.Errorf("open gzip reader: %w", err)
		}
		return gr, nil

	case "zip":
		// archive/zip requires a ReaderAt; buffer the entire body first.
		data, err := io.ReadAll(r)
		if err != nil {
			return nil, fmt.Errorf("buffer zip body: %w", err)
		}
		zr, err := zip.NewReader(bytes.NewReader(data), int64(len(data)))
		if err != nil {
			return nil, fmt.Errorf("open zip: %w", err)
		}
		if len(zr.File) == 0 {
			return nil, fmt.Errorf("zip archive is empty")
		}
		rc, err := zr.File[0].Open()
		if err != nil {
			return nil, fmt.Errorf("open zip entry: %w", err)
		}
		return rc, nil

	default:
		// Plain format (csv, tsv, …) — pass through unchanged.
		return io.NopCloser(r), nil
	}
}

// compressXZ reads from src and writes an xz-compressed file to dst using the
// system xz binary with -9e (maximum/extreme compression).
func compressXZ(ctx context.Context, src io.Reader, dst string) error {
	f, err := os.Create(dst)
	if err != nil {
		return fmt.Errorf("create xz output: %w", err)
	}
	defer f.Close()

	var stderr bytes.Buffer
	cmd := exec.CommandContext(ctx, "xz", "-9e", "-c") //nolint:gosec
	cmd.Stdin = src
	cmd.Stdout = f
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		_ = os.Remove(dst)
		return fmt.Errorf("xz: %w: %s", err, strings.TrimSpace(stderr.String()))
	}
	return nil
}

// openXZ returns a reader over the decompressed content of an xz archive using
// the system xz binary. The returned reader holds the entire decompressed
// content in memory.
func openXZ(ctx context.Context, path string) (io.ReadCloser, error) {
	var stderr bytes.Buffer
	cmd := exec.CommandContext(ctx, "xz", "-d", "-c", path) //nolint:gosec
	cmd.Stderr = &stderr

	out, err := cmd.Output()
	if err != nil {
		return nil, fmt.Errorf("fetch: xz decompress %s: %w: %s",
			path, err, strings.TrimSpace(stderr.String()))
	}
	return io.NopCloser(bytes.NewReader(out)), nil
}

// loadSidecar reads a cacheEntry from a JSON sidecar file.
// Returns (nil, err) if the file is absent or cannot be parsed.
func loadSidecar(path string) (*cacheEntry, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, err
	}
	var entry cacheEntry
	if err := json.Unmarshal(data, &entry); err != nil {
		return nil, fmt.Errorf("fetch: unmarshal sidecar %s: %w", path, err)
	}
	return &entry, nil
}

// saveSidecar writes a cacheEntry to a JSON sidecar file.
func saveSidecar(path string, entry *cacheEntry) error {
	data, err := json.MarshalIndent(entry, "", "  ")
	if err != nil {
		return fmt.Errorf("fetch: marshal sidecar: %w", err)
	}
	return os.WriteFile(path, data, 0o644) //nolint:gosec
}

